/// A simple UUID v4 generator using Dart's Random class.
/// Generates RFC 4122 compliant version 4 UUIDs.
class UUIDGenerator {
  static final Random _random = Random.secure();

  /// Generates a single UUID v4 string.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is any hex digit and y is one of 8, 9, a, or b.
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) — high nibble of byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) — high bits of byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a time-based UUID-like identifier.
  /// Embeds the current timestamp for ordering, combined with random bits.
  /// Format: tttttttt-tttt-4rxx-yxxx-xxxxxxxxxxxx
  static String generateTimeBased() {
    final now = DateTime.now().microsecondsSinceEpoch;
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Embed timestamp in the first 6 bytes (48 bits)
    bytes[0] = (now >> 40) & 0xFF;
    bytes[1] = (now >> 32) & 0xFF;
    bytes[2] = (now >> 24) & 0xFF;
    bytes[3] = (now >> 16) & 0xFF;
    bytes[4] = (now >> 8) & 0xFF;
    bytes[5] = now & 0xFF;

    // Set version to 4
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a short unique ID (8 hex characters) for compact use cases.
  static String generateShort() {
    final now = DateTime.now().microsecondsSinceEpoch;
    final randomPart = _random.nextInt(0xFFFF);
    final combined = ((now & 0xFFFFFFFF) ^ (randomPart << 16)) & 0xFFFFFFFF;
    return combined.toRadixString(16).padLeft(8, '0');
  }

  /// Generates a compact base62 ID of the given length.
  static String generateCompact({int length = 12}) {
    const chars =
        'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    return List.generate(length, (_) => chars[_random.nextInt(chars.length)])
        .join();
  }

  static String _formatAsUUID(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).toList();
    return '${hex.sublist(0, 4).join('')}-'
        '${hex.sublist(4, 6).join('')}-'
        '${hex.sublist(6, 8).join('')}-'
        '${hex.sublist(8, 10).join('')}-'
        '${hex.sublist(10, 16).join('')}';
  }
}

enum UUIDType {
  v4('UUID v4 (Random)', 'Standard RFC 4122 random UUID'),
  timeBased('Time-Based UUID', 'UUID with embedded timestamp for ordering'),
  short('Short ID', 'Compact 8-character hex identifier'),
  compact('Compact ID', 'Base62 alphanumeric identifier');

  final String label;
  final String description;
  const UUIDType(this.label, this.description);
}

