      if (_generatedHistory.length > 100) {
        _generatedHistory.removeLast();
      }
    });
  }

  String _generateByType(UUIDType type) {
    switch (type) {
      case UUIDType.v4:
        return UUIDGenerator.generateV4();
      case UUIDType.timeBased:
        return UUIDGenerator.generateTimeBased();
      case UUIDType.short:
        return UUIDGenerator.generateShort();
      case UUIDType.compact:
        return UUIDGenerator.generateCompact();
    }
  }

  void _generateBatch() {
    setState(() {
      for (int i = 0; i < _batchCount; i++) {
        final uuid = _generateByType(_selectedType);
        _generatedHistory.insert(0, uuid);
      }
      _currentUUID = _generatedHistory.first;
      while (_generatedHistory.length > 100) {
        _generatedHistory.removeLast();
      }
    });
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
