    });

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Record created with ID: ${record.id}'),
        behavior: SnackBarBehavior.floating,
        duration: const Duration(seconds: 2),
      ),
    );
  }

  void _simulateSync() {
    final unsyncedCount =
        _offlineRecords.where((r) => !r.synced).length;
    if (unsyncedCount == 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('All records are already synced!'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    setState(() {
      for (var record in _offlineRecords) {
        record.synced = true;
      }
    });

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('$unsyncedCount record(s) synced successfully!'),
        behavior: SnackBarBehavior.floating,
        backgroundColor: Colors.green,
      ),
    );
  }

  void _clearHistory() {
    setState(() {
      _generatedHistory.clear();
    });
  }

  void _deleteRecord(int index) {
    setState(() {
      _offlineRecords.removeAt(index);
    });
